import openpyxl

wb = openpyxl.load_workbook('/home/gilles/.openclaw-vlmedical/media/inbound/Facturation_2025---5abb4057-4341-49b4-9571-2ec91bc1dc62.xlsx', data_only=True)

ws = wb['Feuil1']

print("FACTURATION VL MEDICAL 2025 — Valeurs calculées\n")

for row in ws.iter_rows(min_row=1, max_row=ws.max_row, values_only=False):
    values = []
    for cell in row:
        v = cell.value
        if v is not None:
            values.append(str(v))
        else:
            values.append('')
    if any(v.strip() for v in values):
        print(' | '.join(values))
